const input = $input.first().json;
const body = input.body ?? input;
const job = body.job ?? {};
const selectedIdea = (job.ideas ?? []).find((idea) => idea.id === body.selectedIdeaId) ?? (job.ideas ?? [])[0] ?? null;
const title = selectedIdea?.title ?? body.seedKeyword ?? 'Untitled topic';
const angle = selectedIdea?.angle ?? 'Build a practical SEO brief';
const research = job.research ?? { objective: '', audience: '', gaps: [], sources: [] };

return [{
  json: {
    eventId: body.eventId,
    jobId: body.jobId,
    callbackUrl: body.callbackUrl,
    callbackSecret: body.callbackSecret,
    brief: {
      title: `${title} | Practical SEO brief`,
      slug: String(title).toLowerCase().replace(/[^a-z0-9?\s-]/g, '').trim().replace(/\s+/g, '-'),
      metaTitle: `${title} | Complete guide`,
      metaDescription: `Structured SEO brief for ${title} with Thai and global context.`,
      audience: research.audience || `Readers searching for ${body.seedKeyword ?? title}`,
      angle,
      outline: [
        `${title}: direct answer and context`,
        'What the reader needs to understand first',
        'Thai-market signals and examples',
        'Global references that strengthen trust',
        'Practical recommendations and cautions',
        'FAQs'
      ],
      faqs: [
        `${body.seedKeyword ?? title} should beginners know what first?`,
        `What mistakes should readers avoid about ${body.seedKeyword ?? title}?`,
        `When should the reader take action immediately?`
      ],
      internalLinks: [
        `${body.seedKeyword ?? title} basics`,
        `${body.seedKeyword ?? title} problems and fixes`,
        `${body.seedKeyword ?? title} buying guide`
      ]
    }
  }
}];
